 88→// Animated number hook for smooth credit transitions
 89→const useAnimatedNumber = (value: number, duration = 600) => {
 90→  const [display, setDisplay] = useState(value);
 91→  const prevValue = useRef(value);
 92→  useEffect(() => {
 93→    if (prevValue.current === value) return;
 94→    const start = prevValue.current;
 95→    const diff = value - start;
 96→    const startTime = performance.now();
 97→    const animate = (now: number) => {
 98→      const progress = Math.min((now - startTime) / duration, 1);
 99→      const eased = 1 - Math.pow(1 - progress, 3);
100→      setDisplay(Math.round(start + diff * eased));
101→      if (progress < 1) requestAnimationFrame(animate);
102→    };
103→    requestAnimationFrame(animate);
104→    prevValue.current = value;
105→  }, [value, duration]);
106→  return display;
107→};
